code.C++:
# cook your dish here
for i in range(int(input())):
    g=int(input())
    s=input()
    r=input()
    count=0
    for j in range(g):
       if s[j]!=r[j]:
           count+=1
    if count%2==0:
        print(1)
    else:
        print(0)

